INSERT INTO sill_pages (slug, title, content, sort_order) VALUES ('a-propos', 'La Société', '<h2>La Société</h2>				\n		<p>La création de la Société Immobilière Lausannoise pour le Logement S.A. (SILL) a été décidée dans le cadre du rapport-préavis N° 2008/59 sur la recapitalisation de la CPCL, adopté le 23 juin 2009. Suite à la dissolution de la Coopérative Colosa, la Municipalité a souhaité créer une nouvelle société anonyme d’investissement immobilier répondant aux critères de développement durable et aux besoins en matière de logements sociaux. Son Conseil d’administration, à l’image de l’ancienne Colosa, est nommé par la Municipalité et la présidence de l’assemblée générale est assurée de droit par le conseiller municipal en charge du logement.</p><p>La SILL est actuellement dotée d’un capital de 52.5 millions de francs. Son but est la promotion de logements à loyers modérés tenant compte des critères du développement durable. Pour atteindre ce but, elle peut procéder à toute opération immobilière, soit acquisition, construction, gérance, administration et vente de tous immeubles, participation à toutes entreprises actives dans le domaine de l’immobilier.</p><p>Les deux missions conjointes de la SILL sont, d’une part, de réaliser prioritairement des immeubles subventionnés ou à loyers contrôlés afin de reprendre le flambeau de Colosa et, d’autre part, en application de ses statuts, de mettre en œuvre des opérations tenant compte de tous les critères de développement durable, incluant des projets conçus selon les méthodes les plus novatrices dans ce domaine.</p><p>Afin de permettre à la nouvelle société de constituer rapidement son parc locatif, la Municipalité lui a initialement réservé sept opérations dans le cadre du préavis «3’000 nouveaux logements»:</p><ul><li>la réalisation de deux immeubles au chemin de la Prairie– opération « Avenue de Provence » (abritant 28 appartements réservés aux aînés et 24 logements à loyers contrôlés) – inaugurés en juin 2013;</li><li>la réalisation d’un immeuble Minergie-P-Eco® de 37 logements au chemin de Bonne-Espérance loués depuis février 2015;</li><li>une opération de deux immeubles implantés à l’avenue de la Sallaz et totalisant 29 logements à loyers contrôlés loués depuis décembre 2015;</li><li>le site du Calvaire – Falaises, en collaboration avec la société coopérative Maison ouvrière (environ 194 logements, dont 50 % pour la SILL):</li><li>la construction de 8 bâtiments Minergie-P-Eco®, sis chemin de Bérée, qui représente 131 logements dont 47 subventionnés, 52 contrôlés et 32 en PPE;</li><li>le développement du lot 11 du quartier des Fiches (185 logements ;</li><li>le développement sur une parcelle située à «En Cojonnex», d’un projet totalisant 255 chambres d’étudiants.</li></ul>		\n															<img width="768" height="1024" src="http://sillsa.ch/wp-content/uploads/2025/10/23-08-23-R1003575-DxO_DeepPRIME-3-1-tk-web-768x1024.jpg" alt="" srcset="https://sillsa.ch/wp-content/uploads/2025/10/23-08-23-R1003575-DxO_DeepPRIME-3-1-tk-web-768x1024.jpg 768w, https://sillsa.ch/wp-content/uploads/2025/10/23-08-23-R1003575-DxO_DeepPRIME-3-1-tk-web-225x300.jpg 225w, https://sillsa.ch/wp-content/uploads/2025/10/23-08-23-R1003575-DxO_DeepPRIME-3-1-tk-web-1152x1536.jpg 1152w, https://sillsa.ch/wp-content/uploads/2025/10/23-08-23-R1003575-DxO_DeepPRIME-3-1-tk-web-1536x2048.jpg 1536w, https://sillsa.ch/wp-content/uploads/2025/10/23-08-23-R1003575-DxO_DeepPRIME-3-1-tk-web-610x813.jpg 610w, https://sillsa.ch/wp-content/uploads/2025/10/23-08-23-R1003575-DxO_DeepPRIME-3-1-tk-web.jpg 1628w" sizes="(max-width: 768px) 100vw, 768px" />', 1);
