INSERT INTO sill_pages (slug, title, content, sort_order) VALUES ('location', 'Location', '<h2>Locataires commerciaux,<br>artisants...</h2>				\n															<img width="800" height="600" src="http://sillsa.ch/wp-content/uploads/2025/04/24-11-27-_GFX0520-1024x768.jpg" alt="" srcset="https://sillsa.ch/wp-content/uploads/2025/04/24-11-27-_GFX0520-1024x768.jpg 1024w, https://sillsa.ch/wp-content/uploads/2025/04/24-11-27-_GFX0520-300x225.jpg 300w, https://sillsa.ch/wp-content/uploads/2025/04/24-11-27-_GFX0520-768x576.jpg 768w, https://sillsa.ch/wp-content/uploads/2025/04/24-11-27-_GFX0520-1536x1152.jpg 1536w, https://sillsa.ch/wp-content/uploads/2025/04/24-11-27-_GFX0520-610x458.jpg 610w, https://sillsa.ch/wp-content/uploads/2025/04/24-11-27-_GFX0520.jpg 2048w" sizes="(max-width: 800px) 100vw, 800px" />															\n		<p>Vous êtes une PME, un indépendant, un artisan ou même un entrepreneur avec un projet à concrétiser et vous cherchez le lieu idéal pour vous établir à Lausanne ? Nous avons ce qu’il vous faut :​ Aux Plaines-du-Loup, dans l’écoquartier quasiment terminé abritant près de 4\'500 nouveaux habitants, à quelques minutes du centre-ville et des grands axes routiers, sur la ligne du futur métro M3.</p><p>Nous vous proposons deux surfaces (133 et 158m2 ) d’activité divisibles et aménageables dans un bâtiment donnant sur la route des Plaines-du-Loup 51a. Ces surfaces sont idéalement positionnées dans le quartier.</p>		\n					<h2>Etre locataire de la SILL SA</h2>				\n		<p>La plupart des appartements propriété de la SILL sont gérés par le Service du logement et des gérances de la Ville de Lausanne.</p><ul><li>Si vous êtes locataires d’un appartement SILL et que vous avez des questions/demandes par rapport à votre location, merci de vous adresser au Service du logement et des gérances de la Ville de Lausanne au 021/315.49.49 (exception: les locataires de l’Avenue de la Sallaz 1-3 doivent s’adresser chez PBBG au 021/345.36.36).</li><li>Si vous cherchez un appartement, accédez à la liste des objets disponibles sur le site Internet de la Ville de Lausanne (renseignements au 021/315.49.49).</li></ul><p> </p><p>Si vous cherchez une place de parc au Plaines-du-Loup, accédez à la liste des objets disponibles, renseignements au 021/315.49.49.</p>		\n															<img width="800" height="533" src="http://sillsa.ch/wp-content/uploads/2025/04/24-06-05-S1000627-1024x682.jpg" alt="" srcset="https://sillsa.ch/wp-content/uploads/2025/04/24-06-05-S1000627-1024x682.jpg 1024w, https://sillsa.ch/wp-content/uploads/2025/04/24-06-05-S1000627-300x200.webp 300w, https://sillsa.ch/wp-content/uploads/2025/04/24-06-05-S1000627-768x511.jpg 768w, https://sillsa.ch/wp-content/uploads/2025/04/24-06-05-S1000627-1536x1022.jpg 1536w, https://sillsa.ch/wp-content/uploads/2025/04/24-06-05-S1000627-610x406.jpg 610w, https://sillsa.ch/wp-content/uploads/2025/04/24-06-05-S1000627.jpg 2048w" sizes="(max-width: 800px) 100vw, 800px" />', 3);
INSERT INTO sill_pages (slug, title, content, sort_order) VALUES ('accueil', 'Accueil', '<img width="800" height="1067" src="http://sillsa.ch/wp-content/uploads/2025/09/IG25_25-06-09-_GFX1707-DxO_DeepPRIME-3.jpg" alt="" srcset="https://sillsa.ch/wp-content/uploads/2025/09/IG25_25-06-09-_GFX1707-DxO_DeepPRIME-3.jpg 1000w, https://sillsa.ch/wp-content/uploads/2025/09/IG25_25-06-09-_GFX1707-DxO_DeepPRIME-3-225x300.jpg 225w, https://sillsa.ch/wp-content/uploads/2025/09/IG25_25-06-09-_GFX1707-DxO_DeepPRIME-3-768x1025.jpg 768w, https://sillsa.ch/wp-content/uploads/2025/09/IG25_25-06-09-_GFX1707-DxO_DeepPRIME-3-610x814.jpg 610w" sizes="(max-width: 800px) 100vw, 800px" />															\n		<p style="text-align: left;"><strong>Société Immobilière </strong><strong>Lausannoise pour </strong><strong>le Logement SA</strong></p><p style="text-align: left;">Fondée par la Ville de Lausanne en 2009, la Société Immobilière Lausannoise pour le Logement SA (SILL) a développé et gère plus de 800 logements, offrant des solutions durables et accessibles au cœur de Lausanne.</p>		\n					<a href="#">\n				<svg aria-hidden="true" viewBox="0 0 192 512" xmlns="http://www.w3.org/2000/svg"><path d="M20 424.229h20V279.771H20c-11.046 0-20-8.954-20-20V212c0-11.046 8.954-20 20-20h112c11.046 0 20 8.954 20 20v212.229h20c11.046 0 20 8.954 20 20V492c0 11.046-8.954 20-20 20H20c-11.046 0-20-8.954-20-20v-47.771c0-11.046 8.954-20 20-20zM96 0C56.235 0 24 32.235 24 72s32.235 72 72 72 72-32.235 72-72S135.764 0 96 0z"></path></svg>			\n									  En savoir plus ...\n					</a>\n					<h2>Actualités</h2>', 4);
INSERT INTO sill_pages (slug, title, content, sort_order) VALUES ('durabilite', 'Aspects environnementaux', '<h2>ESG - Un portefeuille des plus performant</h2>				\n															<img width="842" height="596" src="http://sillsa.ch/wp-content/uploads/2025/08/ESG24.png" alt="" srcset="https://sillsa.ch/wp-content/uploads/2025/08/ESG24.png 842w, https://sillsa.ch/wp-content/uploads/2025/08/ESG24-300x212.png 300w, https://sillsa.ch/wp-content/uploads/2025/08/ESG24-768x544.png 768w, https://sillsa.ch/wp-content/uploads/2025/08/ESG24-610x432.png 610w" sizes="(max-width: 842px) 100vw, 842px" />															\n		<p>Aspects environnementaux<br />et gestion des charges du parc immobilier</p>		\n															<img width="800" height="534" src="http://sillsa.ch/wp-content/uploads/2025/10/23-04-24-W1000023-Modifier_0123-1-tk-web-2048x1367.jpg" alt="" srcset="https://sillsa.ch/wp-content/uploads/2025/10/23-04-24-W1000023-Modifier_0123-1-tk-web-2048x1367.jpg 2048w, https://sillsa.ch/wp-content/uploads/2025/10/23-04-24-W1000023-Modifier_0123-1-tk-web-300x200.jpg 300w, https://sillsa.ch/wp-content/uploads/2025/10/23-04-24-W1000023-Modifier_0123-1-tk-web-1024x683.jpg 1024w, https://sillsa.ch/wp-content/uploads/2025/10/23-04-24-W1000023-Modifier_0123-1-tk-web-768x512.jpg 768w, https://sillsa.ch/wp-content/uploads/2025/10/23-04-24-W1000023-Modifier_0123-1-tk-web-1536x1025.jpg 1536w, https://sillsa.ch/wp-content/uploads/2025/10/23-04-24-W1000023-Modifier_0123-1-tk-web-610x407.jpg 610w" sizes="(max-width: 800px) 100vw, 800px" />															\n		<h4>Un leadership environnemental reconnu</h4><p>SILL SA se positionne comme un acteur exemplaire de l’immobilier durable avec des performances qui dépassent largement les attentes du marché. <br />Impact Carbone Minimal <br />Les émissions totales de CO2 de notre portefeuille s’élèvent à 245 tonnes pour la période d’analyse ce qui correspond à des émissions par m² de 4.56 kgCO2/ m², soit une diminution de -0.44  % par rapport à la période d’analyse 2023.</p><h4>Consommation thermique</h4><p>La consommation thermique totale du parc s’élève à 3’255’488.00 kWh, soit une diminution de -0.35  % par rapport à la période précédente. En conséquence, l’indice de dépense de chaleur moyen (IDC) s’élève à 218 MJ/m2, soit une augmentation de 3.32 % par rapport à la période 2023.<br />En comparant l’IDC moyen de 2024 avec celui de 2023, il est possible d’évaluer les baisses des consommations thermiques, l’IDC étant corrigé par un facteur climatique. La baisse des températures de chauffage constatée un peu partout en Suisse et l’effort fourni par chacun d’entre nous, a permis de réduire les consommations d’énergie thermique massivement et ainsi de diminuer les émissions de CO2.</p><h4>Consommation d’eau</h4><p>Notre consommation d’eau s’élève à 1,04 m³/m², un niveau cohérent avec la forte densité d’occupation de nos logements familiaux (4 à 6 personnes par appartement de 4,5 pièces).</p><h4>Chiffres clés du portefeuille</h4><p><strong>Parc 100 % certifié Minergie</strong><br />Tous nos immeubles respectent les plus hauts standards<br /><strong>Énergies renouvelables</strong> <br />79 % de notre parc fonctionne avec des sources propres<br /><strong>Surveillance complète</strong><br />100  % de nos bâtiments sont surveillés en continu</p><h4>Innovation et anticipation</h4><p>Tous nos logements disposent de compteurs individuels, permettant un suivi précis et une facturation équitable des consommations.</p><h4>Notre engagement durable</h4><p>se traduit par :</p><ul><li>Un suivi rigoureux des installations techniques</li><li>Une recherche permanente de solutions innovantes</li><li>Une sensibilisation des locataires aux bonnes pratiques</li></ul> <p>Cette performance démontre ainsi qu’il est possible de réconcilier avec succès qualité de vie, responsabilité environnementale et viabilité économique.</p>', 5);
INSERT INTO sill_pages (slug, title, content, sort_order) VALUES ('a-propos-2', 'Le Conseil d\'administration', '<h2>Le Conseil d\'administration</h2>				\n		<p><strong>NATACHA LITZISTORF</strong><br />Directrice du logement, de l’environnement et de l’architecture<br />Présidente</p><p><strong>YVES FERRARI</strong> <br />Vice-président</p><p><strong>ANDREA EGGLI</strong></p><p><strong>SARRA PERRIN</strong></p><p><strong>JEAN-PIERRE FENIELLO</strong></p><p><strong>ME PIERRE NOVERRAZ</strong></p><p><strong>JULIEN EGGENBERGER</strong></p><p><strong>ANDREA FAUCHERRE</strong></p>		\n															<img width="800" height="1000" src="http://sillsa.ch/wp-content/uploads/2025/10/24-02-26-L1004560-DxO_DeepPRIME-3-Modifier_0120-Modifier_0121-1-tk-web-1638x2048.jpg" alt="" srcset="https://sillsa.ch/wp-content/uploads/2025/10/24-02-26-L1004560-DxO_DeepPRIME-3-Modifier_0120-Modifier_0121-1-tk-web-1638x2048.jpg 1638w, https://sillsa.ch/wp-content/uploads/2025/10/24-02-26-L1004560-DxO_DeepPRIME-3-Modifier_0120-Modifier_0121-1-tk-web-240x300.jpg 240w, https://sillsa.ch/wp-content/uploads/2025/10/24-02-26-L1004560-DxO_DeepPRIME-3-Modifier_0120-Modifier_0121-1-tk-web-819x1024.jpg 819w, https://sillsa.ch/wp-content/uploads/2025/10/24-02-26-L1004560-DxO_DeepPRIME-3-Modifier_0120-Modifier_0121-1-tk-web-768x960.jpg 768w, https://sillsa.ch/wp-content/uploads/2025/10/24-02-26-L1004560-DxO_DeepPRIME-3-Modifier_0120-Modifier_0121-1-tk-web-1229x1536.jpg 1229w, https://sillsa.ch/wp-content/uploads/2025/10/24-02-26-L1004560-DxO_DeepPRIME-3-Modifier_0120-Modifier_0121-1-tk-web-610x763.jpg 610w, https://sillsa.ch/wp-content/uploads/2025/10/24-02-26-L1004560-DxO_DeepPRIME-3-Modifier_0120-Modifier_0121-1-tk-web.jpg 1736w" sizes="(max-width: 800px) 100vw, 800px" />', 6);
INSERT INTO sill_pages (slug, title, content, sort_order) VALUES ('lorganisation', 'L\'organisation', '<h2>L\'organisation</h2>				\n		<p><strong>SYLVIE TRAIMOND<br></strong>Codirectrice<strong></strong></p><p><strong>PIERRE MENOUX</strong><br>Architecte EPF, Codirecteur</p>\n<p><strong>SAMUEL VARONE</strong><br>Responsable Finances</p>\n<p><strong>PATRICIA LIBOUTON</strong><br>Architecte</p>\n<p><strong>OPHELIE COISNE</strong><br>Architecte</p>', 7);
INSERT INTO sill_pages (slug, title, content, sort_order) VALUES ('aspects-societaux', 'Aspects sociétaux', '<h2>Les aspects sociétaux</h2>				\n					<h3>Nos concierges : piliers essentiels du vivre ensemble</h3>				\n															<img width="1200" height="799" src="http://sillsa.ch/wp-content/uploads/2025/05/SILL_nosConcierges.jpg" alt="" srcset="https://sillsa.ch/wp-content/uploads/2025/05/SILL_nosConcierges.jpg 1200w, https://sillsa.ch/wp-content/uploads/2025/05/SILL_nosConcierges-300x200.jpg 300w, https://sillsa.ch/wp-content/uploads/2025/05/SILL_nosConcierges-1024x682.jpg 1024w, https://sillsa.ch/wp-content/uploads/2025/05/SILL_nosConcierges-768x511.jpg 768w, https://sillsa.ch/wp-content/uploads/2025/05/SILL_nosConcierges-610x406.jpg 610w" sizes="(max-width: 1200px) 100vw, 1200px" />															\n		<p>Les concierges de la SILL incarnent bien plus qu’une simple fonction d’entretien. Ils sont les véritables gardiens du lien social au sein de nos immeubles, jouant un rôle crucial dans le bien-être de nos résidents et la qualité de vie de nos quartiers.</p><p>Leur professionnalisme exemplaire se manifeste quotidiennement à travers une multitude de tâches. De l’entretien méticuleux des espaces communs à la gestion des petites réparations, en passant par la coordination avec les services techniques, nos concierges assurent le bon fonctionnement de nos bâtiments avec une efficacité remarquable.</p><p>Mais c’est surtout par leur personnalité chaleureuse et leur écoute attentive que nos concierges se distinguent. Véritables âmes de nos immeubles, ils créent une atmosphère accueillante et rassurante pour tous les résidents. Leur présence bienveillante favorise un sentiment de sécurité et de confiance, particulièrement apprécié par les personnes âgées ou vulnérables.</p><p>En tant que médiateurs discrets mais essentiels, nos concierges jouent un rôle clé dans la prévention et la résolution des conflits entre voisins. Leur capacité à faciliter la communication et à promouvoir le respect mutuel contribue grandement à l’harmonie au sein de nos immeubles.</p><p>L’impact positif de nos concierges s’étend bien au-delà des murs de nos bâtiments. En veillant au bon entretien des espaces extérieurs et en organisant parfois des événements conviviaux, ils participent activement à l’amélioration de la qualité de vie dans nos quartiers.</p><p>Véritables piliers du vivre ensemble, nos concierges incarnent les valeurs de proximité, de solidarité et de service qui sont au cœur de la mission de la SILL. Leur dévouement quotidien mérite notre plus profonde reconnaissance, car ils contribuent de manière significative à faire de nos immeubles des lieux de vie agréables et épanouissants pour tous nos locataires.</p>', 8);
