INSERT INTO sill_timeline (slug, title, event_date, category, description, image_id, link_url, sort_order) VALUES ('2015-augmentation-majeure-capital-chf-52-5-millions', '2015 - Augmentation Majeure Capital CHF 52.5 millions', '2015-02-15', 'strategie_financiere', 'Augmentation majeure du capital de CHF 32.5 millions, portant le total à CHF 52.5 millions. Cette injection de fonds propres permet à la SILL d\'accélérer le développement.', NULL, NULL, 6);
